def patched_class_call(original, self, *args, **kwargs):
    """
    This method is used for patching class methods of gemini SDKs.
    This patch creates a span and set input and output of the original method to the span.
    """
    from mlflow.tracing.distributed import get_tracing_context_headers_for_http_request
    headers = get_tracing_context_headers_for_http_request()
    if headers:
        # gemini SDK uses config.http_options.headers
        config = kwargs.get("config", {})
        if isinstance(config, dict):
            http_options = config.get("http_options", {})
            if not isinstance(http_options, dict):
                http_options = {}
            http_options.setdefault("headers", {}).update(headers)
            config["http_options"] = http_options
            kwargs["config"] = config
        else:
            # assume config object with attributes
            if not hasattr(config, "http_options"):
                from google.genai.types import HttpOptions
                config.http_options = HttpOptions(headers={})
            elif config.http_options is None:
                from google.genai.types import HttpOptions
                config.http_options = HttpOptions(headers={})
            if config.http_options.headers is None:
                config.http_options.headers = {}
            config.http_options.headers.update(headers)
    with TracingSession(original, self, args, kwargs) as manager:
        output = original(self, *args, **kwargs)
        manager.output = output
        return output

